resource "aws_elasticbeanstalk_environment" "main" {
  name                = "my-eb-env"
  description         = "My Elastic Beanstalk Environment"
  platform            = "Node.js 6.16.0 LTS" # Choose your preferred platform
  tier {
    name   = "WebServer"
    type   = "Standard"
    version = "1.0"
  }
  settings {
    service {
      type = "Web"
    }
    scaling {
      min_instances = 2
      max_instances = 5

      auto_scaling_group {
        name = "awseb-e-xxxxx-st" # This will be generated by EB
      }

      triggers {
        measure_name = "CPUUtilization"
        statistic    = "Average"
        unit         = "Percent"
        lower_threshold = 30
        upper_threshold = 70
        period       = 60
        evaluation_periods = 2
      }
    }
  }
  option_settings {
    namespace = "aws:elasticbeanstalk:environment"
    option_name = "EnvironmentType"
    value = "SingleInstance"
  }
}

resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = "aws_elasticbeanstalk_ec2_role" # Replace with your specific EC2 role ARN
}

resource "aws_rds_instance" "my_db1" {
  identifier             = "my-db1"
  allocated_storage      = 20
  engine                 = "mysql"
  instance_class         = "db.t2.micro"
  name                   = "mydb"
  username               = "admin"
  password               = "your_password" # Replace with a secure password.
  skip_final_snapshot    = true
  multi_az               = false
  db_subnet_group_name   = "default" # Replace if needed.
