resource "aws_lex_bot" "pizza_order" {
  name        = "PizzaOrderBot"
  role_arn    = "arn:aws:iam::123456789012:role/LexBotRole" # Replace with your Lex bot role ARN
  intents {
    name        = "OrderPizzaIntent"
    slots {
      name        = "pizzaType"
      slot_type   = "AMAZON.Food"
      slot_constraint = "Required"
      prompt      = "What kind of pizza would you like to order?"
    }
    slots {
      name        = "pizzaSize"
      slot_type   = "AMAZON.NUMBER"
      slot_constraint = "Required"
      prompt      = "What size pizza would you like? (Small, Medium, Large)"
    }
    sample_utterances = [
      "I want to order a {pizzaType} pizza",
      "Can I get a {pizzaType} pizza?",
      "Order a {pizzaSize} {pizzaType} pizza"
    ]
    fulfillment_activity {
      type           = "ReturnIntent"
      return_intent = true
    }
    follow_up_intent {
      name = "ConfirmOrderIntent"
      prompt = "Is this correct? You want to order a {pizzaType} {pizzaSize} pizza?"
    }
  }

  voice_role_arn = "arn:aws:polly:us-east-1:123456789012:voice/Joanna" # Replace with your Polly Voice ARN
}

resource "aws_lex_intent" "confirm_order" {
  name              = "ConfirmOrderIntent"
  bot_name          = aws_lex_bot.pizza_order.name
  slots {
    name        = "confirmation"
    slot_type   = "AMAZON.Boolean"
    slot_constraint = "Required"
    prompt      = "Yes or No?"
  }
  sample_utterances = [
    "Yes",
    "No",
    "Confirm",
    "Cancel"
  ]

