    description              = "Size of pizza to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.NUMBER"
    priority                 = 2
    value_elicitation_prompt {
      message {
        content             = "What size of pizza would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
