variable "cluster_name" {
  type        = string
  description = "The name of the EKS cluster"
}

resource "aws_iam_role" "eks_cluster_role" {
  name = "${var.cluster_name}-eks-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "eks.amazonaws.com"
        },
        Effect = "Allow",
        Sid    = ""
      }
    ]
  })
}

resource "aws_iam_policy" "eks_cluster_policy" {
  name        = "${var.cluster_name}-eks-policy"
  description = "Policy for EKS cluster"
  policy      = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action   = "eks:*",
        Effect   = "Allow",
        Resources = "*"
      }
    ]
  })
}

resource "aws_iam_policy_attachment" "eks_cluster_attachment" {
  role       = aws_iam_role.eks_cluster_role.name
  policy_arn = aws_iam_policy.eks_cluster_policy.arn
}

resource "aws_eks_cluster" "example" {
  name     = var.cluster_name
  role_arn = aws_iam_role.eks_cluster_role.arn

  vpc_config {
    subnet_ids = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyyyyy"] # Replace with actual subnet IDs
  }

  depends_on = [aws_iam_policy_attachment.eks_cluster_attachment]

  provisioner "local-exec" {
    command = "aws eks update-kubeconfig --name ${var.cluster_name} --region ${var.region}"
    when    = "create"
  }

  provisioner "local-exec" {
    command = "aws eks update-kubeconfig --name ${var.cluster_name} --region ${var.region} --remove-cluster"
    when    = "destroy"
  }
}

