terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "aws" {
  region = "us-east-1" # Replace with your desired region
}

data "aws_caller_identity" "current" {}

# Optional: Fetch latest stable ECR image
data "aws_ecr_repository" "repo" {
  name = "your-ecr-repo-name" # Replace with your ECR repository name
}

data "aws_ecr_image" "stable" {
  repository_name = data.aws_ecr_repository.repo.name
  image_tag      = "stable"
}

locals {
  image_tag = data.aws_ecr_image.stable.image_id != null ? data.aws_ecr_image.stable.image_id : "latest" #Using image ID or latest if not found
  aws_tags = {
    Environment = "dev"
    Terraform   = "true"
  }
  workspace_name = "my-eks-cluster"
}

# EKS Module - Replace with appropriate module source and variables
module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "19.17.3"

  cluster_name    = local.workspace_name
  cluster_version = "1.28"

  vpc_id     = "your-vpc-id" # Replace with your VPC ID
  subnet_ids = ["your-subnet-id-1", "your-subnet-id-2"] # Replace with your Subnet IDs

  # IAM
  create_iam_role = true
  eks_managed_policy_arn = "arn:aws:iam::aws:policy/AdministratorAccess"

  # Instance
  instance_types = ["t3.medium"]
  desired_capacity = 2
  min_size = 1
  max_size = 3

  # Other configurations can be added here

  tags = local.aws_tags
}

# Output EKS Cluster Information
output "cluster_name" {
  value = module.eks.cluster_name
}

output "cluster_endpoint" {
  value = module.eks.cluster_endpoint
}

output "cluster_certificate_arn" {
  value = module.eks.cluster_certificate_arn
}

output "kubeconfig" {
  value = module.eks.kubeconfig
}

# Configure Helm Provider
provider "helm" {
  kubernetes {
    host                   = module.eks.cluster_endpoint
    cluster_ca_certificate = module.eks.cluster_certificate_arn
    token                  = data.aws_eks_cluster_auth_info.current.token
  }
}

# Configure Kubernetes Provider
provider "kubernetes" {
  host                   = module.eks.cluster_endpoint
  cluster_ca_certificate = module.eks.cluster_certificate_arn
  token                  = data.aws_eks_cluster_auth_info.current.token
}

data "aws_eks_cluster_auth_info" "current" {
  cluster_name = module.eks.cluster_name
}

