extracted_code:
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "public" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  map_public_ip_on_launch = true
  tags = {
    Name = "public-subnet"
  }
}

resource "aws_subnet" "private" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "private-subnet"
  }
}

resource "aws_launch_template" "ec2_fleet_lt" {
  name_prefix   = "ec2-fleet-lt-"
  image_id      = "ami-0c55b2ab9d25735ce" # Latest Amazon Linux 2 AMI - replace with the correct AMI for your region
  instance_type = "t3.micro"
}

resource "aws_ec2_fleet" "example" {
  name = "ec2-fleet-example"
  target_capacity_type = "spot"
  spot_price           = "0.05"

  launch_template_configs {
    launch_template_id = aws_launch_template.ec2_fleet_lt.id
    override = {
      instance_type = "t3.micro"
    }
  } 

  allocation_strategy = "lowest-price"

  fleet_capacity = 9

  launch_templates = [
    {
      launch_template_id = aws_launch_template.ec2_fleet_lt.id
      weight = 5
    },
    {
      launch_template_id = aws_launch_template.ec2_fleet_lt.id
      weight = 4
      spot_price = "0.04"
    }
  ]
}

