resource "aws_msk_cluster" "example" {
  cluster_name           = "msk-cluster"
  kafka_version          = "2.8.1"
  number_of_broker_nodes = 3
  broker_node_group {
    client_subnets = ["subnet-xxxxxxxxxxxxxxxxx", "subnet-yyyyyyyyyyyyyyyyy"]
    security_groups = ["sg-xxxxxxxxxxxxxxxxx"]
    instance_type = "kafka.m5.large"
  }
  configuration_info {
    arn      = "arn:aws:kafka:us-west-2:123456789012:configuration/msk-config"
    revision = 1
  }
  encryption_info {
    encryption_at_rest_kms_key_id = "alias/msk-key"
  }
  open_monitoring {
    prometheus {
      arn = "arn:aws:prometheus:us-west-2:123456789012:alertmanager/msk-prometheus"
      port = 9094
    }
  }

  client_authentication {
    tls {
      certificate_authority_arns = ["arn:aws:certmgr:us-west-2:123456789012:certificate/xxxxxxxx-xxxx-xxxx-xxxx-xxxxxxxxxxxx"]
    }
  }

  tags = {
    Name = "example-msk-cluster"
  }
}

resource "aws_cloudwatch_log_group" "msk_logs" {
  name              = "/aws/msk/cluster/msk-cluster"
  retention_in_days = 30
}

resource "aws_s3_bucket" "msk_s3_bucket" {
  bucket = "msk-cluster-logs"
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose"
  destination = "s3"
  s3_destination {
    bucket        = aws_s3_bucket.msk_s3_bucket.id
    prefix        = "msk-logs/"
    role_arn      = "arn:aws:iam::123456789012:role/msk_firehose_role"
  }
}
resource "aws_msk_connect_custom_plugin" "example" {
  name        = "debezium-plugin"
  location_s3 = "s3://msk-plugin-bucket/debezium.zip"
}

resource "aws_msk_connect_connector" "example" {
  name             = "debezium-connector"
  cluster_id       = aws_msk_cluster.example.id
  custom_plugin {
    location_s3 = aws_msk_connect_custom_plugin.example.location_s3
    name = aws_msk_connect_custom_plugin.example.name
  }
  capacity {
    auto_scaling {
      max_capacity = 5
      min_capacity = 1
    }
  }
  configuration = {
    "connector.class" = "io.debezium.connector.mongodb.MongoDbConnector"
  }
  status = "ACTIVE"
}
