resource "aws_vpc" "autograder_vpc" {
  cidr_block           = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true

  tags = {
    Name = "Autograder VPC"
  }
}

resource "aws_subnet" "autograder_subnet" {
  vpc_id            = aws_vpc.autograder_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"

  tags = {
    Name = "Autograder Subnet"
  }
}

resource "aws_internet_gateway" "autograder_igw" {
  vpc_id = aws_vpc.autograder_vpc.id

  tags = {
    Name = "Autograder IGW"
  }
}

resource "aws_route_table" "autograder_route_table" {
  vpc_id = aws_vpc.autograder_vpc.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.autograder_igw.id
  }

  tags = {
    Name = "Autograder Route Table"
  }
}

resource "aws_route_table_association" "autograder_route_table_association" {
  subnet_id      = aws_subnet.autograder_subnet.id
  route_table_id = aws_route_table.autograder_route_table.id
}

resource "aws_security_group" "autograder_sg" {
  name        = "autograder-sg"
  description = "Security group for autograder CodeBuild"
  vpc_id      = aws_vpc.autograder_vpc.id

  ingress {
    from_port   = 22
    to_port     = 22
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Restrict this in production
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "Autograder Security Group"
  }
}

resource "aws_codebuild_project" "autograder_project" {
  name         = "autograder-project"
  description  = "CodeBuild project for autograding"
  service_role = "arn:aws:iam::YOUR_ACCOUNT_ID:role/CodeBuildServiceRole" # Replace with your CodeBuild service role ARN

  source {
    type = "GITHUB"
    auth {
      type = "OAUTH"
    }
    location = "YOUR_GITHUB_REPO" # Replace with your GitHub repo
  }

  environment {
    compute_type                = "BUILD_GENERAL1_SMALL"
    image                       = "aws/codebuild/standard:5.0"
    type                        = "LINUX"
    privileged_mode             = false
    environment_variables = {
      "STUDENT_CODE_DIR" = "/tmp/student_code"
    }
  }

  vpc_config {
    security_group_ids = [aws_security_group.autograder_sg.id]
    subnet_ids         = [aws_subnet.autograder_subnet.id]
  }

  artifacts {
    type = "NO_ARTIFACTS"
  }
}

