resource "aws_api_gateway_rest_api" "caas" {
  name        = "caas"
  description = "API Gateway for CaaS"
}

resource "aws_api_gateway_resource" "caas_cat" {
  rest_api_id = aws_api_gateway_rest_api.caas.id
  path_part   = "cat"
}

resource "aws_api_gateway_method" "caas_get" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "GET"
  authorization = "NONE"
}

resource "aws_api_gateway_method" "caas_put" {
  rest_api_id   = aws_api_gateway_rest_api.caas.id
  resource_id   = aws_api_gateway_resource.caas_cat.id
  http_method   = "PUT"
  authorization = "NONE"
}

resource "aws_lambda_function" "caas_get_lambda" {
  # Replace with actual Lambda function code and configuration
  function_name = "caas_get_lambda"
  runtime       = "nodejs18.x"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  zip_file      = file("lambda_code_get.zip")
}

resource "aws_lambda_function" "caas_put_lambda" {
  # Replace with actual Lambda function code and configuration
  function_name = "caas_put_lambda"
  runtime       = "nodejs18.x"
  role          = aws_iam_role.lambda_role.arn
  handler       = "index.handler"
  zip_file      = file("lambda_code_put.zip")
}

resource "aws_api_gateway_integration" "caas_get_integration" {
  rest_api_id       = aws_api_gateway_rest_api.caas.id
  resource_id       = aws_api_gateway_resource.caas_cat.id
  http_method       = aws_api_gateway_method.caas_get.http_method
  type              = "AWS_PROXY"
  integration_http_method = "POST" # or GET depending on lambda trigger
  uri               = aws_lambda_function.caas_get_lambda.invoke_arn
}

resource "aws_api_gateway_integration" "caas_put_integration" {
  rest_api_id       = aws_api_gateway_rest_api.caas.id
  resource_id       = aws_api_gateway_resource.caas_cat.id
  http_method       = aws_api_gateway_method.caas_put.http_method
  type              = "AWS_PROXY"
  integration_http_method = "POST" # or GET depending on lambda trigger
  uri               = aws_lambda_function.caas_put_lambda.invoke_arn
}

resource "aws_s3_bucket" "cat_pictures" {
  bucket = "cat-pictures-bucket-unique"
}

resource "aws_dynamodb_table" "cat_data" {
  name             = "catData"
  billing_mode     = "PAY_PER_REQUEST"
  hash_key         = "name"
  attribute {
    name = "name"
    type = "S"
  }
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_role"
  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Principal = {
          Service = "lambda.amazonaws.com"
        },
        Effect = "Allow",
        Sid = ""
      },
    ]
  })
}

resource "aws_iam_policy" "lambda_s3_access" {
  name        = "lambda_s3_access"
  description = "Allow Lambda to read from S3"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetObject"
        ],
        Effect   = "Allow",
        Resource = "${aws_s3_bucket.cat_pictures.arn}/*"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_s3_attachment" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_s3_access.arn
}

resource "aws_iam_policy" "lambda_dynamodb_access" {
  name        = "lambda_dynamodb_access"
  description = "Allow Lambda to access DynamoDB"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "dynamodb:GetItem",
          "dynamodb:PutItem",
          "dynamodb:UpdateItem",
          "dynamodb:DeleteItem",
          "dynamodb:Query",
          "dynamodb:Scan"
        ],
        Effect   = "Allow",
        Resource = "${aws_dynamodb_table.cat_data.arn}"
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lambda_dynamodb_attachment" {
  role       = aws_iam_role.lambda_role.name
  policy_arn = aws_iam_policy.lambda_dynamodb_access.arn
}
```

