resource "aws_dlm_lifecycle_policy" "example" {
  policy_name = "my-dlm-policy"
  target_tags = {
    Key   = "glacier-vault"
    Value = "my-glacier-vault"
  }

  policy_definition {
    schedule_name = "my-schedule"
    schedule = "cron(0 1 * * ? *)" # Run at 1:00 AM UTC every day

