      authorization_endpoint       = "https://example.com/auth"
      token_endpoint               = "https://example.com/token"
      scope                        = "openid"
      session_timeout              = 3600
      on_unauthenticated {
        secure_redirect {
          status_code = "HTTP_302"
          protocol    = "HTTPS"
          host        = "example.com"
